      if (!address || !mint || typeof address !== 'string' || typeof mint !== 'string') {
        return res.status(400).json({ error: 'Missing address or mint parameter' });
      }

      const heliusKey = process.env.HELIUS_API_KEY || process.env.SOLANA_RPC_API_KEY;
