      .limit(1);

    if (account.length === 0) return;

    const current = parseFloat(account[0].unclaimedBalance);
    const decrease = parseFloat(amount);
    const newBalance = Math.max(0, current - decrease).toString();

    await db
      .update(referralTokenAccounts)
