    if (status === 'all') {
      return await db
        .select()
        .from(socialTasks)
        .orderBy(desc(socialTasks.createdAt))
        .limit(limit);
    }
    return await db
      .select()
      .from(socialTasks)
      .where(eq(socialTasks.status, status))
      .orderBy(desc(socialTasks.createdAt))
      .limit(limit);
  }

