                              +{parseFloat(tx.referralFeeAmount).toFixed(6)} SOL
                            </p>
                            <p className="text-xs text-purple-300">
                              From {parseFloat(tx.originalFeeAmount).toFixed(6)} SOL fee
                            </p>
                          </div>
