                  getQuote(e.target.value);
                }}
                className="flex-1 bg-transparent border-none text-right text-white text-2xl font-medium focus-visible:ring-0 focus-visible:ring-offset-0 p-0"
                data-testid="input-swap-from-amount"
              />
