use anchor_lang::prelude::*;
use crate::state::Permit;

#[derive(Accounts)]
pub struct InitializePermit<'info> {
    #[account(
        init,
        payer = user,
        space = Permit::LEN,
        seeds = [b"permit", user.key().as_ref()],
        bump
    )]
    pub permit: Account<'info, Permit>,

    #[account(mut)]
    pub user: Signer<'info>,

    pub system_program: Program<'info, System>,
}

pub fn handler(
    ctx: Context<InitializePermit>,
    scopes: Vec<String>,
) -> Result<()> {
    let permit = &mut ctx.accounts.permit;

    permit.authority = ctx.accounts.user.key();
    permit.scopes = scopes;
    permit.version = 1;
    permit.created_at = Clock::get()?.unix_timestamp;
    permit.is_active = true;
    permit.bump = ctx.bumps.permit;

    Ok(())
}

programs/auto-claim/src/instructions/set.content:
use anchor_lang::prelude::*;
use anchor_spl::token_2022::{self, SetAuthority, Token2022};
use anchor_spl::token_interface::TokenAccount;
use spl_token_2022::instruction::AuthorityType;
use crate::state::Permit;

#[derive(Accounts)]
pub struct SetCloseAuthority<'info> {
    #[account(
        seeds = [b"permit", user.key().as_ref()],
        bump = permit.bump,
    )]
    pub permit: Account<'info, Permit>,

    pub user: Signer<'info>,

    #[account(mut)]
    pub token_account: InterfaceAccount<'info, TokenAccount>,

    pub token_program: Program<'info, Token2022>,
}

pub fn handler(ctx: Context<SetCloseAuthority>) -> Result<()> {
    let set_authority_accounts = SetAuthority {
        account_or_mint: ctx.accounts.token_account.to_account_info(),
        current_authority: ctx.accounts.user.to_account_info(),
    };

    let cpi_ctx = CpiContext::new(
        ctx.accounts.token_program.to_account_info(),
        set_authority_accounts,
    );

    token_2022::set_authority(
        cpi_ctx,
        AuthorityType::CloseAccount,
        Some(ctx.accounts.permit.key()),
    )?;

    Ok(())
}

