                      <div className={`w-8 h-8 rounded-full bg-gradient-to-br from-purple-500 to-pink-500 flex items-center justify-center text-white text-sm font-bold flex-shrink-0 ${reserve.logoUrl ? 'hidden' : ''}`}>
                        {displaySymbol.substring(0, 1)}
                      </div>
                      <div className="text-white font-medium text-sm">{displaySymbol}</div>
                    </div>
                    <div className="flex items-center gap-1.5 pl-10">
                      <Badge variant={reserve.platform === 'Backpack' ? 'default' : 'secondary'} className={`text-xs ${reserve.platform === 'Backpack' ? 'bg-blue-600 text-white' : 'bg-orange-600 text-white'}`}>
                        {reserve.platform}
                      </Badge>
                      {reserve.capabilities?.comingSoon && (
                        <Badge variant="outline" className="border-yellow-500/50 text-yellow-300 text-xs gap-1">
                          <Clock className="w-2.5 h-2.5" />
                          Soon
                        </Badge>
                      )}
                    </div>
                  </div>

                  {/* APY Column */}
                  <div className="flex items-center justify-center">
                    <span className={`font-semibold text-sm ${getAPYColor(reserve.depositAPY, displaySymbol)}`}>
                      {reserve.depositAPY.toFixed(1)}%
                    </span>
                  </div>

                  {/* TVL Column */}
                  <div className="flex items-center justify-end">
                    <div className="text-white font-medium text-sm">{formatTVL(tvl, displaySymbol)}</div>
                  </div>
                </div>

                {/* Bottom Row: Deposited, Earnings */}
                <div className="grid grid-cols-2 gap-3 pl-10">
                  {/* Deposited */}
                  <div>
                    <div className="text-xs text-purple-300 mb-0.5">Deposited</div>
                    {(() => {
                      if (!userPosition) {
                        return <div className="text-purple-300 text-sm">0.00 {displaySymbol}</div>;
                      }
                      const formatted = formatAmount(userPosition.amount, reserve.decimals || 6, displaySymbol, true, parseFloat(reserve.price || '0')) as any;
                      return (
                        <>
                          <div className="text-white text-sm font-medium">{formatted.token}</div>
                          <div className="text-purple-300 text-xs">{formatted.usd}</div>
                        </>
                      );
                    })()}
                  </div>

                  {/* Earnings */}
                  <div>
                    <div className="text-xs text-purple-300 mb-0.5">Earnings</div>
                    {(() => {
                      if (!userPosition) {
                        return <div className="text-purple-300 text-sm">0.00 {displaySymbol}</div>;
                      }
                      const formatted = formatAmount(userPosition.earnings || '0', reserve.decimals || 6, displaySymbol, true, parseFloat(reserve.price || '0')) as any;
                      return (
                        <>
                          <div className="text-white text-sm font-medium">{formatted.token}</div>
                          <div className="text-purple-300 text-xs">{formatted.usd}</div>
                        </>
                      );
                    })()}
                  </div>
                </div>
              </div>
            );
          })}
        </div>
      </CardContent>
    </Card>
  );
}

server/decodeKaminoTx.ts.content:
import { Connection, PublicKey } from '@solana/web3.js';

const RPC_URL = process.env.HELIUS_RPC_URL || 'https://api.mainnet-beta.solana.com';

// Known transaction with deposit instruction
const EXAMPLE_TX = '5gdFycd5naLS6TiKciN8KjjsdUAvMVBhgcBtNd6iSgaqKN4B685BDwF8bDbfE5NoDdbDiNXyB7LPMRzseJjVhwQv';

async function decodeTransaction() {
  console.log('🔍 Decoding Kamino kVault transaction...');

  const connection = new Connection(RPC_URL);

  try {
    const tx = await connection.getTransaction(EXAMPLE_TX, {
      maxSupportedTransactionVersion: 0
    });

    if (!tx || !tx.transaction) {
      throw new Error('Transaction not found');
    }

    const message = tx.transaction.message;
    const accountKeys = message.staticAccountKeys;

    console.log(`\n✅ Full account list for transaction (${accountKeys.length} accounts):\n`);
    accountKeys.forEach((key, idx) => {
      console.log(`[${idx.toString().padStart(2, '0')}] ${key.toBase58()}`);
    });

    // Find the kVault instruction
    const instructions = message.compiledInstructions;
    const kVaultIx = instructions.find(ix => {
      const programKey = accountKeys[ix.programIdIndex];
      return programKey.toBase58() === 'KvauGMspG5k6rtzrqqn7WNn3oZdyKqLKwK2XWQ8FLjd';
    });

    if (kVaultIx) {
      console.log(`\n📋 kVault Instruction Details:`);
      console.log(`  Program Index: [${kVaultIx.programIdIndex}]`);
      console.log(`  Data (hex): ${Buffer.from(kVaultIx.data).toString('hex')}`);
      console.log(`  Data (base64): ${Buffer.from(kVaultIx.data).toString('base64')}`);
      console.log(`\n  Account Indexes (${kVaultIx.accountKeyIndexes.length}):`);

      kVaultIx.accountKeyIndexes.forEach((idx, position) => {
        const key = accountKeys[idx];
        console.log(`    [${position.toString().padStart(2, '0')}] -> [${idx.toString().padStart(2, '0')}] ${key.toBase58()}`);
      });
    }

  } catch (error: any) {
    console.error('❌ Error:', error.message);
  }
}

decodeTransaction();

server/fetchKaminoIdl.ts.content:
import { Connection, PublicKey } from '@solana/web3.js';
import { Program, AnchorProvider, Idl } from '@coral-xyz/anchor';
import fs from 'fs';
import path from 'path';

const KAMINO_KLEND_IDL_ADDRESS = '6LtLpnUFNByNXLyCoK9wA2MykKAmQNZKBdY8s47dehDc';
const RPC_URL = process.env.HELIUS_RPC_URL || 'https://api.mainnet-beta.solana.com';

async function fetchAndSaveIdl() {
  console.log('🔄 Fetching Kamino KLend IDL from on-chain...');

  const connection = new Connection(RPC_URL);

  try {
    // Fetch IDL from on-chain address
    const idl = await Program.fetchIdl(new PublicKey(KAMINO_KLEND_IDL_ADDRESS), {
      connection,
    } as any);

    if (!idl) {
      throw new Error('IDL not found on-chain');
    }

    // Create directory
    const dir = path.join(process.cwd(), 'programs', 'kamino');
    if (!fs.existsSync(dir)) {
      fs.mkdirSync(dir, { recursive: true });
    }

    // Save IDL
    const filePath = path.join(dir, 'klend-idl.json');
    fs.writeFileSync(filePath, JSON.stringify(idl, null, 2));

    console.log('✅ Kamino KLend IDL saved to:', filePath);
    console.log('📊 Instructions found:', idl.instructions?.length || 0);
  } catch (error) {
    console.error('❌ Failed to fetch IDL:', error);
    throw error;
  }
}

fetchAndSaveIdl();

